output.message:
{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Select Pelvic CT Volume",
      "simple": "Choose the pelvic CT scan from the volume list.",
      "detailed": "This step loads the correct preoperative CT scan of the pelvis into the planning workspace. Accurate segmentation and fracture analysis depend on selecting the right volume. From the dropdown, select the pelvic CT volume you wish to use for planning."
    },
    {
      "step_id": "cb_step_2",
      "title": "Segment the Pelvis",
      "simple": "Click the 'Run Step 1: Segment Pelvis' button to automatically segment the pelvic bone.",
      "detailed": "This automated step identifies and outlines the entire pelvic bone from the CT scan, creating a 3D segmentation that will serve as the foundation for fracture analysis and subsequent planning. Click the button to start the segmentation."
    },
    {
      "step_id": "cb_step_3",
      "title": "Identify Fracture Lines",
      "simple": "Click 'Run Step 2: Segment Fractures' to automatically detect and segment fracture fragments.",
      "detailed": "This step analyzes the pelvic bone for discontinuities and separates the bone into individual fracture fragments. Each fragment will be highlighted and available for assessment and reduction planning. Click the button to run fracture segmentation."
    },
    {
      "step_id": "cb_step_4",
      "title": "Exclude Unwanted Fragments",
      "simple": "Untick any fracture fragments you want to exclude from the planning process.",
      "detailed": "Some small or non-displaced fragments may not require surgical attention. By unchecking them, you remove them from subsequent steps such as template generation and screw planning, focusing only on clinically relevant fragments. Review the list and untick those that should be ignored."
    },
    {
      "step_id": "cb_step_5",
      "title": "Generate Reduction Template",
      "simple": "Click 'Run Step 3: Generate Template' to create a template for fracture reduction.",
      "detailed": "This step creates a 3D model that serves as a template for reducing the fractures back to anatomical alignment. The template incorporates the selected fragments and the healthy pelvic anatomy as a guide. Click the button to generate the template."
    },
    {
      "step_id": "cb_step_6",
      "title": "Register and Reduce Fragments",
      "simple": "Click 'Run Step 4: Register _Reduce' to automatically align and reduce the fracture fragments.",
      "detailed": "This step performs an automated registration that moves the fracture fragments into their intended anatomical positions relative to the pelvis, simulating the surgical reduction. The result is a reduced pelvis model ready for screw planning. Click the button to run the registration."
    },
    {
      "step_id": "cb_step_7",
      "title": "Assess Need for Manual Adjustment",
      "simple": "If further adjustments are needed, tick the 'Manually adjust a fragment' checkbox. Otherwise, proceed.",
      "detailed": "After automated reduction, some fragments may not be perfectly aligned. This step gives you the option to manually refine the position of any fragment. If the reduction looks satisfactory, leave the checkbox unticked and continue to screw planning. Tick the checkbox if you need to adjust any fragment."
    },
    {
      "step_id": "cb_step_8",
      "title": "Choose Fragment for Adjustment",
      "simple": "From the 'Fragment' dropdown, select the fragment you want to manually adjust.",
      "detailed": "If you decided to make manual adjustments, now choose which fragment to refine. The drop-down lists all available fragments from the reduced pelvis. Select the one that needs repositioning or rotation to improve alignment."
    },
    {
      "step_id": "cb_step_9",
      "title": "Adjust Fragment Pose",
      "simple": "Use the transform tools to translate and rotate the selected fragment until it fits correctly.",
      "detailed": "This step allows you to fine-tune the position and orientation of the chosen fracture fragment using interactive 3D tools. Clinical judgment is key: aim for anatomical alignment with the adjacent pelvic anatomy. Once satisfied, click 'Done' to confirm the adjustment."
    },
    {
      "step_id": "cb_step_10",
      "title": "Apply Manual Adjustments",
      "simple": "Click the 'Apply adjustments' button to incorporate your manual changes into the plan.",
      "detailed": "After adjusting the fragment's position, this button commits the new pose into the planning model. It updates the reduced pelvis state, ensuring subsequent steps use the corrected fragment alignment. Click to apply."
    },
    {
      "step_id": "cb_step_11",
      "title": "Plan Screw Trajectories",
      "simple": "Click 'Run Step 5: Plan Screws' to automatically generate screw trajectories for fixation.",
      "detailed": "This automated step designs optimal screw paths to stabilize the reduced pelvic fractures. Based on the fragment positions and bone anatomy, it proposes screw trajectories that provide maximal purchase and avoid critical structures. Click the button to generate the screw plan."
    },
    {
      "step_id": "cb_step_12",
      "title": "Decide Whether to Edit Screws",
      "simple": "If you need to modify screw trajectories, tick the 'Edit Screw trajectories' checkbox. Otherwise, the plan is complete.",
      "detailed": "The automatically generated screws may need refinement to better suit the patient's anatomy or surgical approach. This step lets you choose to manually edit the trajectories. If the proposed plan is acceptable, leave it unchecked and finish. Tick the checkbox to adjust screw paths."
    },
    {
      "step_id": "cb_step_13",
      "title": "Adjust Screw Trajectories",
      "simple": "Use the transform tools to modify the position and rotation of the screw trajectories as needed.",
      "detailed": "Here you can fine-tune each screw's path to improve bone purchase, avoid joint surfaces, or optimize placement for your surgical approach. Adjust the trajectories interactively in the 3D view. Click 'Done' when each screw is positioned correctly."
    },
    {
      "step_id": "cb_step_14",
      "title": "Regenerate Screws",
      "simple": "Click 'Regenerate screws from edited lines' to finalize the edited screw trajectories.",
      "detailed": "After manually adjusting the screw paths, this step recalculates the screw geometries to match the new lines. This ensures the final screw models reflect your intended placement. Click the button to regenerate."
    },
    {
      "step_id": "cb_step_15",
      "title": "Finalize Screw Planning",
      "simple": "Untick the 'Edit Screw trajectories' checkbox to confirm the screw plan is complete.",
      "detailed": "Once you are satisfied with the screw trajectories, uncheck this box to exit edit mode. This finalizes the screw planning step and completes the preoperative plan. The plan is now ready for review and export."
    }
  ]
}
